mapper.insert:
insert into biz_backpacker_profile (
    user_id, copper_coins, reputation_score, last_checkin_date,
    completed_tasks, failed_tasks, create_time, update_time
) values (
    #{userId}, #{copperCoins}, #{reputationScore}, #{lastCheckinDate},
    #{completedTasks}, #{failedTasks}, #{createTime}, #{updateTime}
)

mapper.update:
update biz_backpacker_profile
set copper_coins = copper_coins - #{amount},
    update_time = sysdate()
where user_id = #{userId}
  and copper_coins >= #{amount}

mapper.insert:
insert into biz_coin_transaction (
    user_id, amount, balance_after, tx_type, ref_id, remark, create_time
) values (
    #{userId}, #{amount}, #{balanceAfter}, #{txType}, #{refId}, #{remark}, #{createTime}
)

mapper.select:
select transaction_id, user_id, amount, balance_after, tx_type, ref_id, remark, create_time
from biz_coin_transaction
where user_id = #{userId}
order by create_time desc
limit #{limit}
